  // ===== Block-of-3 alike components (base premium examples) =====
  it.todo("quote base premium for 2 runes is 50 G (no block)");
  it.todo("quote base premium for 3 runes is 60 G (block applies)");
  it.todo("quote base premium for 4 runes is 100 G (no block — block requires exactly 3)");
