  it.todo("claim references more swords damaged than insured (2 sword damages, 1 sword insured) → error / rejection");

  // ===== Claim: cap and insurance sum =====
  it.todo("policy with sword + amulet has insurance sum 1600 G and cap 3200 G");
  it.todo("policy with cursed sword has cap 2000 G (based on unmodified insurance value; premium modifiers don't raise cap)");
  it.todo("policy with sword + 3 runes (block) has insurance sum 1750 G (block discount affects premium only, not insurance sum)");

  // ===== Claim: cap exhaustion across successive claims =====
  it.todo("sword insured (cap 2000 G), first claim of 1500 G → payout 1400 G, remainingCap 600 G");
  it.todo("after first claim used 1400 G, second claim of 1500 G → payout 600 G (reduced to remaining cap), remainingCap 0 G");

  // ===== Claim: payout rounding =====
  it.todo("payout calculation yielding 350.5 G is rounded DOWN to 350 G (in MHPCO's favor)");

  // ===== Edge cases / errors =====
  it.todo("quote with unknown item type (e.g. broomstick) → error");
  it.todo("claim references damage to item not in policy (e.g. amulet damaged when only sword insured) → error");
  it.todo("claim references damage to unknown item type → error");
  it.todo("claim with negative damage amount → error");

  // ===== CLI =====
  it.todo("CLI reads JSON scenario from stdin and writes JSON results to stdout (schema-example scenario)");
  it.todo("CLI exits with non-zero status on unknown item type in quote; writes error to stderr; no results on stdout");
  it.todo("CLI exits with non-zero status when claim references item not in policy; writes error to stderr");
  it.todo("CLI exits with non-zero status when claim contains negative damage amount; writes error to stderr");
  it.todo("CLI exits with non-zero status when claim has more damages of a type than policy covers");
});

